// Merge status response with stored clip data
const statusData = $input.first().json;
const storedData = $('💾 Store Request ID1').item.json;

return [{
  json: {
    status: statusData.status,
    request_id: storedData.request_id,
    clip_id: storedData.clip_id,
    clip_prompt: storedData.clip_prompt,
    video_title: storedData.video_title,
    video_description: storedData.video_description,
    video_tags: storedData.video_tags,
    total_clips: storedData.total_clips
  }
}];

// Get video file size for YouTube resumable upload header
const { execSync } = require('child_process');

let fileSize;
try {
  fileSize = parseInt(execSync('stat -c%s /tmp/video_final.mp4').toString().trim());
} catch(e) {
  throw new Error('Could not read video file size. FFmpeg may have failed: ' + e.message);
}

if (!fileSize || fileSize < 1000) {
  throw new Error(`Video file is missing or too small (${fileSize} bytes). Check FFmpeg output.`);
}

const prevData = $('🎞️ Build FFmpeg Command1').item.json;

return [{
  json: {
    file_size: fileSize,
    video_title: prevData.video_title,
    video_description: prevData.video_description,
    video_tags: prevData.video_tags,
    output_path: prevData.output_path
  }
}];

// Read video file as binary and attach it for the upload node
const { execSync } = require('child_process');

let binaryData;
try {
  const videoBuffer = execSync('cat /tmp/video_final.mp4');
  binaryData = await this.helpers.prepareBinaryData(
    videoBuffer,
    'video_final.mp4',
    'video/mp4'
  );
} catch(e) {
  throw new Error('Failed to read video file for upload: ' + e.message);
}

const prevData = $input.first().json;

return [{
  json: {
    upload_url: prevData.upload_url,
    video_title: prevData.video_title
  },
  binary: {
    video_data: binaryData
  }
}];

// Parse Gemini response
const responseText = $input.first().json.candidates[0].content.parts[0].text;

// Clean JSON — remove markdown code fences if Gemini adds them
let cleanJson = responseText
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

let concept;
try {
  concept = JSON.parse(cleanJson);
} catch(e) {
  // Fallback concept if parsing fails
  concept = {
    title: "Earth's Most Breathtaking Moments",
    description: "Witness the raw beauty of our planet in stunning 4K.",
    tags: ["nature", "earth", "4K", "cinematic", "shorts"],
    topic: "Natural wonders of the world",
    clips: [
      { id: 1, prompt: "Cinematic aerial view of northern lights over snowy mountains, photorealistic, 4K, slow camera drift" },
      { id: 2, prompt: "Massive ocean wave crashing in slow motion, golden hour light, photorealistic, 4K" },
      { id: 3, prompt: "Time-lapse of volcanic lava flowing into ocean at night, glowing red, photorealistic, 4K" },
      { id: 4, prompt: "Dense rainforest canopy from above, morning mist, sunbeams, photorealistic, 4K cinematic" }
    ]
  };
}

// Ensure exactly 4 clips for ~20s total output
const clips = concept.clips.slice(0, 4);

// Output each clip as a separate item for parallel processing
return clips.map(clip => ({
  json: {
    clip_id: clip.id,
    clip_prompt: clip.prompt,
    video_title: concept.title,
    video_description: concept.description,
    video_tags: concept.tags,
    video_topic: concept.topic,
    total_clips: clips.length
  }
}));

// Store request_id with clip info for polling
const item = $input.first().json;
const clipData = $('🧩 Parse Script & Split Clips1').item.json;

if (!item.request_id) {
  throw new Error('No request_id returned from fal.ai. Check your API key and endpoint.');
}

return [{
  json: {
    request_id: item.request_id,
    clip_id: clipData.clip_id,
    clip_prompt: clipData.clip_prompt,
    video_title: clipData.video_title,
    video_description: clipData.video_description,
    video_tags: clipData.video_tags,
    total_clips: clipData.total_clips,
    status: 'submitted'
  }
}];

// Extract video URL from fal.ai result
const result = $input.first().json;
const prevData = $('🔄 Merge Status + Clip Data').item.json;

// fal.ai can return video URL at different paths depending on model version
const videoUrl = 
  result?.video?.url ||
  result?.output?.video?.url ||
  result?.videos?.[0]?.url ||
  result?.output?.videos?.[0]?.url ||
  '';

if (!videoUrl) {
  throw new Error(`No video URL found in fal.ai response for clip ${prevData.clip_id}. Response: ${JSON.stringify(result)}`);
}

return [{
  json: {
    clip_id: prevData.clip_id,
    video_url: videoUrl,
    video_title: prevData.video_title,
    video_description: prevData.video_description,
    video_tags: prevData.video_tags,
    total_clips: prevData.total_clips
  }
}];

// Build FFmpeg command to download and stitch all clips
const clips = $input.first().json.data;

// Sort clips by clip_id to maintain correct order
clips.sort((a, b) => a.clip_id - b.clip_id);

const videoTitle = clips[0].video_title;
const videoDescription = clips[0].video_description;
const videoTags = clips[0].video_tags;

// Build wget commands to download each clip
const downloadCmds = clips.map((clip, i) =>
  `wget -q -O /tmp/clip_${String(i + 1).padStart(2, '0')}.mp4 "${clip.video_url}"`
).join('\n');

// Build FFmpeg concat list content
const concatList = clips.map((_, i) =>
  `file '/tmp/clip_${String(i + 1).padStart(2, '0')}.mp4'`
).join('\n');

// Estimate total duration for audio fade (4 clips x 5s = ~20s)
const totalDuration = clips.length * 5;
const fadeStart = Math.max(totalDuration - 3, 1);

// Full command pipeline:
// 1. Download clips
// 2. Concatenate with FFmpeg (copy streams, no re-encode for speed)
// 3. Add background music with fade-out
// 4. Cleanup temp files
const ffmpegCmd = [
  `printf '${concatList.replace(/'/g, "'\\''")}' > /tmp/concat_list.txt`,
  `ffmpeg -f concat -safe 0 -i /tmp/concat_list.txt -c copy /tmp/video_raw.mp4 -y`,
  `ffmpeg -i /tmp/video_raw.mp4 -stream_loop -1 -i /opt/music/background.mp3 -map 0:v -map 1:a -shortest -af "afade=t=out:st=${fadeStart}:d=3" -c:v copy -c:a aac -b:a 128k /tmp/video_final.mp4 -y`,
  `rm -f /tmp/clip_*.mp4 /tmp/concat_list.txt /tmp/video_raw.mp4`
].join('\n');

return [{
  json: {
    download_commands: downloadCmds,
    ffmpeg_command: ffmpegCmd,
    video_title: videoTitle,
    video_description: videoDescription,
    video_tags: videoTags,
    output_path: '/tmp/video_final.mp4',
    clips_count: clips.length,
    estimated_duration_seconds: totalDuration
  }
}];

// Extract the resumable upload URL from YouTube's Location header
const response = $input.first().json;

// When fullResponse=true, headers are at response.headers
const uploadUrl = 
  response.headers?.location ||
  response.headers?.Location ||
  '';

if (!uploadUrl) {
  throw new Error('No upload URL returned from YouTube. Check OAuth credentials and quota. Response: ' + JSON.stringify(response.headers));
}

const videoTitle = $('📐 Get File Size').item.json.video_title;

return [{
  json: {
    upload_url: uploadUrl,
    video_title: videoTitle,
    status: 'ready_to_upload'
  }
}];

const uploadResult = $input.first().json;
const title = $('📁 Read Video as Binary').item.json.video_title;
const videoId = uploadResult.id || 'unknown';

// Cleanup temp file
const { execSync } = require('child_process');
try { execSync('rm -f /tmp/video_final.mp4'); } catch(e) { /* ignore */ }

console.log(`Video uploaded: https://youtube.com/watch?v=${videoId}`);

return [{
  json: {
    success: true,
    video_id: videoId,
    video_url: `https://youtube.com/watch?v=${videoId}`,
    youtube_shorts_url: `https://youtube.com/shorts/${videoId}`,
    title: title,
    uploaded_at: new Date().toISOString()
  }
}];
